solution.code:
def to_bcd(n):
    if n < 0: n = 0
    return "0b" + "".join(bin(int(d))[2:].zfill(4) for d in str(n))

if __name__ == "__main__":
    print(f"12 in BCD: {to_bcd(12)}")
